CREATE TABLE IF NOT EXISTS valorapesquisa.result_scores (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid REFERENCES valorapesquisa.organizations(id), response_id uuid NOT NULL REFERENCES valorapesquisa.responses(id), total_score numeric(10,2), max_score numeric(10,2), percentage numeric(10,2), maturity_level text, maturity_label text, radar_text text, strategic_truth text, risk_if_nothing_changes text, next_level text, devolutiva_json jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), created_by uuid, updated_by uuid, is_deleted boolean NOT NULL DEFAULT false);
CREATE TABLE IF NOT EXISTS valorapesquisa.dimension_scores (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid REFERENCES valorapesquisa.organizations(id), response_id uuid NOT NULL REFERENCES valorapesquisa.responses(id), dimension_name text NOT NULL, score numeric(10,2), max_score numeric(10,2), percentage numeric(10,2), level_label text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), created_by uuid, updated_by uuid, is_deleted boolean NOT NULL DEFAULT false);
